const response = items[0]?.json ?? {};
if (Array.isArray(response.errors) && response.errors.length) {
  const messages = response.errors.map((error) => error.message).join('; ');
  throw new Error(`Wiki.js list pages GraphQL error: ${messages}`);
}

const pages = response.data?.pages?.list ?? response.pages?.list;
if (!Array.isArray(pages)) {
  throw new Error('Wiki.js list pages response did not include data.pages.list. Check the GraphQL schema and API token.');
}

return pages
  .filter((page) => page && page.id !== undefined && page.id !== null)
  .filter((page) => page.isPublished !== false)
  .map((page) => ({
    json: {
      page_id: String(page.id),
      page_id_number: Number(page.id),
      path: page.path ?? '',
      title: page.title ?? page.path ?? `Wiki.js page ${page.id}`,
      locale: page.locale ?? null,
      description: page.description ?? null,
      updated_at: page.updatedAt ?? null,
      created_at: page.createdAt ?? null,
    },
  }));

if (Array.isArray($json.errors) && $json.errors.length) {
  const messages = $json.errors.map((error) => error.message).join('; ');
  throw new Error(`Wiki.js page content GraphQL error: ${messages}`);
}

const page = $json.data?.pages?.single ?? $json.pages?.single;
if (!page) {
  throw new Error('Wiki.js returned no page content. Check the page permissions and API token.');
}

const wikiBaseUrl = 'http://localhost:3000';
const rawContent = page.content || page.render || '';

const stripHtml = (value) => String(value)
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ');

const normalizeText = (value) => stripHtml(value)
  .replace(/```[\s\S]*?```/g, (block) => `\n${block}\n`)
  .replace(/\r\n/g, '\n')
  .replace(/[\t ]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const hashText = (value) => {
  let h1 = 0xdeadbeef;
  let h2 = 0x41c6ce57;
  for (let i = 0; i < value.length; i += 1) {
    const ch = value.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return `${(h2 >>> 0).toString(16).padStart(8, '0')}${(h1 >>> 0).toString(16).padStart(8, '0')}`;
};

const chunkText = (text, maxLength = 1200, overlap = 180) => {
  if (!text) return [];
  const blocks = text.split(/\n(?=#{1,6}\s)|\n\n+/).map((block) => block.trim()).filter(Boolean);
  const chunks = [];
  let current = '';

  const pushCurrent = () => {
    const trimmed = current.trim();
    if (trimmed) chunks.push(trimmed);
    current = '';
  };

  for (const block of blocks) {
    if (block.length > maxLength) {
      pushCurrent();
      for (let start = 0; start < block.length; start += maxLength - overlap) {
        chunks.push(block.slice(start, start + maxLength).trim());
      }
      continue;
    }

    const candidate = current ? `${current}\n\n${block}` : block;
    if (candidate.length > maxLength) {
      pushCurrent();
      current = block;
    } else {
      current = candidate;
    }
  }

  pushCurrent();
  return chunks;
};

const text = normalizeText(rawContent);
const contentHash = hashText([page.id, page.path, page.updatedAt, text].join('\n'));
const wikiUrl = wikiBaseUrl && page.path ? `${wikiBaseUrl}/${String(page.path).replace(/^\/+/, '')}` : null;
const chunks = chunkText(text);
const indexedAt = new Date().toISOString();

return chunks.map((chunk, index) => ({
  json: {
    page_id: String(page.id),
    chunk_index: index,
    chunk_count: chunks.length,
    chunk_text: chunk,
    path: page.path ?? '',
    title: page.title ?? page.path ?? `Wiki.js page ${page.id}`,
    wiki_url: wikiUrl,
    last_seen_updated_at: page.updatedAt ?? null,
    content_hash: contentHash,
    indexed_at: indexedAt,
    metadata: {
      source: 'wikijs',
      page_id: String(page.id),
      path: page.path ?? '',
      title: page.title ?? page.path ?? `Wiki.js page ${page.id}`,
      wiki_url: wikiUrl,
      locale: page.locale ?? null,
      editor: page.editor ?? null,
      created_at: page.createdAt ?? null,
      updated_at: page.updatedAt ?? null,
      chunk_index: index,
      chunk_count: chunks.length,
    },
  },
}));
